mapper.insert:
INSERT IGNORE INTO bluenote_im.im_conversation_member (
    id, conversation_id, user_id, peer_user_id, member_role, member_status,
    last_read_seq, last_received_seq, unread_count, pinned, mute, hidden,
    last_visible_seq, created_at, updated_at
) VALUES (
    #{id}, #{conversationId}, #{userId}, #{peerUserId}, #{memberRole}, #{memberStatus},
    #{lastReadSeq}, #{lastReceivedSeq}, #{unreadCount}, #{pinned}, #{mute}, #{hidden},
    #{lastVisibleSeq}, #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT m.id, m.conversation_id, m.user_id, m.peer_user_id, m.member_role, m.member_status, m.last_read_seq, m.last_received_seq, m.unread_count, m.pinned, m.mute, m.hidden, m.last_visible_seq, m.created_at, m.updated_at, c.current_seq, c.last_message_id, c.last_message_at FROM bluenote_im.im_conversation_member m JOIN bluenote_im.im_conversation c ON c.conversation_id = m.conversation_id WHERE m.user_id = #{userId} AND m.hidden = 0 AND m.member_status = 'NORMAL'
AND ( COALESCE(c.last_message_at, c.created_at) < #{cursorLastMessageAt} OR (COALESCE(c.last_message_at, c.created_at) = #{cursorLastMessageAt} AND m.conversation_id < #{cursorConversationId}) )
ORDER BY m.pinned DESC, COALESCE(c.last_message_at, c.created_at) DESC, m.conversation_id DESC LIMIT #{size}

mapper.update:
UPDATE bluenote_im.im_conversation_member
SET hidden = 0,
    updated_at = #{updatedAt}
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}

UPDATE bluenote_im.im_conversation_member
SET hidden = 0,
    last_read_seq = GREATEST(last_read_seq, #{seq}),
    last_received_seq = GREATEST(last_received_seq, #{seq}),
    updated_at = #{updatedAt}
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}

UPDATE bluenote_im.im_conversation_member
SET hidden = 0,
    unread_count = unread_count + 1,
    updated_at = #{updatedAt}
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}

UPDATE bluenote_im.im_conversation_member
SET last_received_seq = GREATEST(last_received_seq, #{seq}),
    updated_at = #{updatedAt}
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}

UPDATE bluenote_im.im_conversation_member
SET last_read_seq = GREATEST(last_read_seq, #{seq}),
    unread_count = #{unreadCount},
    updated_at = #{updatedAt}
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}

UPDATE bluenote_im.im_conversation_member
SET

    pinned = #{pinned},


    mute = #{mute},

    updated_at = #{updatedAt}
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}

UPDATE bluenote_im.im_conversation_member
SET hidden = 1,
    unread_count = 0,
    last_visible_seq = GREATEST(last_visible_seq, #{lastVisibleSeq}),
    last_read_seq = GREATEST(last_read_seq, #{lastVisibleSeq}),
    updated_at = #{updatedAt}
WHERE conversation_id = #{conversationId}
  AND user_id = #{userId}
